let currentEventId = null;
let selectedSeatIds = [];
let lastOrderId = null;
let discoveryMode = "search";
let discoveryPage = 0;
let discoveryTotal = 0;
let discoverySize = 8;

function getAuthToken() {
  return window.localStorage.getItem("silverstage.authToken") || "";
}

function authHeaders(extraHeaders) {
  const headers = Object.assign({}, extraHeaders || {});
  const token = getAuthToken();
  if (token) {
    headers["X-Auth-Token"] = token;
  }
  return headers;
}

function renderHierarchyTree(hierarchy) {
  const seasons = hierarchy.seasons || [];
  if (seasons.length === 0) {
    return "<p>No seasons configured for this event yet.</p>";
  }

  const seasonBlocks = seasons
    .map((season) => {
      const sessions = season.sessions || [];
      const sessionBlocks = sessions
        .map((session) => {
          const zones = session.zones || [];
          const zoneBlocks = zones
            .map((zone) => {
              const seats = zone.seats || [];
              const seatBlocks = seats
                .map((seat) => `<li>${seat.seatNumber} (${seat.status})</li>`)
                .join("");
              return `<li><strong>${zone.code}</strong> - ${zone.name} (cap: ${zone.capacity})<ul>${seatBlocks}</ul></li>`;
            })
            .join("");
          return `<li>${session.title} (${session.startTime})<ul>${zoneBlocks}</ul></li>`;
        })
        .join("");
      return `<li><strong>${season.name}</strong><ul>${sessionBlocks}</ul></li>`;
    })
    .join("");

  return `<ul>${seasonBlocks}</ul>`;
}

function populateSessionSelector(hierarchy) {
  const $session = $("#session-select");
  $session.empty();
  const sessions = [];

  (hierarchy.seasons || []).forEach((season) => {
    (season.sessions || []).forEach((session) => {
      sessions.push(session);
    });
  });

  if (!sessions.length) {
    $session.append('<option value="">No sessions</option>');
    return;
  }

  sessions.forEach((session) => {
    $session.append(
      `<option value="${session.id}">${session.title} (${session.startTime})</option>`,
    );
  });
}

function renderTicketOptions(ticketTypes) {
  if (!ticketTypes.length) {
    $("#ticket-options").html("No ticket options configured for this event.");
    return;
  }

  const rows = ticketTypes
    .map((type) => {
      const tier = (type.tierRules || [])
        .map((rule) => `min ${rule.minQuantity}: $${rule.price}`)
        .join(", ");
      return `<li><strong>${type.name}</strong> (${type.code}) | ${type.visibilityScope} | ${type.saleWindowLabel}<br/>Tiers: ${tier}</li>`;
    })
    .join("");
  $("#ticket-options").html(`<ul>${rows}</ul>`);
}

function loadTicketTypes(eventId) {
  const $ticketType = $("#ticket-type-select");
  $ticketType.empty().append('<option value="">Loading...</option>');

  $.getJSON(`/api/events/${eventId}/ticket-types`)
    .done((ticketTypes) => {
      $ticketType.empty();
      if (!ticketTypes.length) {
        $ticketType.append('<option value="">No ticket types</option>');
      } else {
        ticketTypes.forEach((type) => {
          $ticketType.append(
            `<option value="${type.id}">${type.name} | ${type.visibilityScope}</option>`,
          );
        });
      }
      renderTicketOptions(ticketTypes);
    })
    .fail(() => {
      $ticketType.empty().append('<option value="">Error</option>');
      $("#ticket-options").text("Unable to load ticket options.");
    });
}

function loadHierarchy(eventId) {
  currentEventId = eventId;
  $("#hierarchy-container").html("Loading hierarchy...");
  $.getJSON(`/api/events/${eventId}/hierarchy`)
    .done((response) => {
      $("#hierarchy-container").html(renderHierarchyTree(response));
      populateSessionSelector(response);
      loadTicketTypes(eventId);
    })
    .fail(() => {
      $("#hierarchy-container").text(
        "Failed to load hierarchy from local API.",
      );
    });
}

function renderSeatMap(response) {
  const zoneBlocks = (response.zones || [])
    .map((zone) => {
      const seats = (zone.seats || [])
        .map((seat) => {
          const disabled = seat.status !== "AVAILABLE" ? "disabled" : "";
          const classes = `seat ${seat.status.toLowerCase()} ${selectedSeatIds.includes(seat.seatId) ? "selected" : ""}`;
          return `<button type="button" class="${classes}" data-seat-id="${seat.seatId}" ${disabled}>${seat.seatNumber}</button>`;
        })
        .join("");
      return `<div class="zone-block"><h4>${zone.zoneCode} - ${zone.zoneName}</h4><div class="seat-grid">${seats}</div></div>`;
    })
    .join("");

  $("#seat-map").html(zoneBlocks || "No seats configured for this session.");

  if (response.quotaReached) {
    $("#inventory-alert")
      .text("Quota reached for selected channel. Choose another channel.")
      .addClass("alert-danger");
  } else if (response.lowInventory) {
    $("#inventory-alert")
      .text(
        `Low inventory warning: only ${response.remainingQuota} seats left in this channel.`,
      )
      .addClass("alert-warning");
  } else if (
    response.remainingQuota !== null &&
    response.remainingQuota !== undefined
  ) {
    $("#inventory-alert")
      .text(`Remaining channel inventory: ${response.remainingQuota}`)
      .removeClass("alert-danger alert-warning");
  } else {
    $("#inventory-alert").text(
      "Select ticket option and channel to see quota alerts.",
    );
  }
}

function loadSeatMap() {
  const sessionId = $("#session-select").val();
  const ticketTypeId = $("#ticket-type-select").val();
  const channel = $("#channel-select").val();

  if (!sessionId) {
    $("#seat-map").text("Please select a session first.");
    return;
  }

  let query = "";
  if (ticketTypeId) {
    query = `?ticketTypeId=${ticketTypeId}&channel=${channel}`;
  }

  $.getJSON(`/api/sessions/${sessionId}/seat-map${query}`)
    .done((response) => {
      renderSeatMap(response);
    })
    .fail((xhr) => {
      const msg =
        xhr.responseJSON && xhr.responseJSON.message
          ? xhr.responseJSON.message
          : "Failed to load seat map.";
      $("#seat-map").text(msg);
    });
}

function loadEvents() {
  const $list = $("#event-list");
  $list.empty().append("<li>Loading local events...</li>");

  $.getJSON("/api/events")
    .done((events) => {
      $list.empty();
      if (!events.length) {
        $list.append("<li>No events found in local database.</li>");
        return;
      }

      events.forEach((event) => {
        const item = `
                    <li class="event-card">
                        <div>
                            <strong>${event.name}</strong>
                            <span>${event.code} | ${event.startDate} to ${event.endDate}</span>
                        </div>
                        <button type="button" class="open-hierarchy" data-event-id="${event.id}">Open hierarchy</button>
                    </li>
                `;
        $list.append(item);
      });
    })
    .fail(() => {
      $list.empty().append("<li>Unable to read local events API.</li>");
    });
}

$(document).on("click", ".open-hierarchy", function () {
  const eventId = $(this).data("event-id");
  selectedSeatIds = [];
  loadHierarchy(eventId);
});

$(document).on("click", ".seat.available", function () {
  const seatId = Number($(this).data("seat-id"));
  if (selectedSeatIds.includes(seatId)) {
    selectedSeatIds = selectedSeatIds.filter((id) => id !== seatId);
    $(this).removeClass("selected");
  } else {
    selectedSeatIds.push(seatId);
    $(this).addClass("selected");
  }
});

$("#load-seat-map").on("click", function () {
  selectedSeatIds = [];
  loadSeatMap();
});

$("#reserve-seats").on("click", function () {
  const sessionId = $("#session-select").val();
  const ticketTypeId = $("#ticket-type-select").val();
  const channel = $("#channel-select").val();

  if (
    !currentEventId ||
    !sessionId ||
    !ticketTypeId ||
    !selectedSeatIds.length
  ) {
    $("#order-status").text(
      "Select event, session, ticket option, and seats first.",
    );
    return;
  }

  const payload = {
    eventId: Number(currentEventId),
    sessionId: Number(sessionId),
    ticketTypeId: Number(ticketTypeId),
    orderCode: `ORD-${Date.now()}`,
    buyerReference: "SeniorPortalUser",
    channel,
    seatIds: selectedSeatIds,
  };

  $.ajax({
    url: "/api/seat-orders",
    method: "POST",
    headers: authHeaders(),
    contentType: "application/json",
    data: JSON.stringify(payload),
  })
    .done((response) => {
      lastOrderId = response.orderId;
      selectedSeatIds = [];
      $("#order-status").html(
        `Order ${response.orderCode} created. Hold until ${response.holdExpiresAt}. Unpaid auto-cancel at ${response.cancelExpiresAt}.`,
      );
      loadSeatMap();
    })
    .fail((xhr) => {
