});

$("#browse-announcements").on("click", function () {
  browseDiscovery("announcements", 0);
});

$("#prev-page").on("click", function () {
  if (discoveryPage === 0) {
    return;
  }
  const nextPage = discoveryPage - 1;
  if (discoveryMode === "search") {
    runSearch(nextPage);
  } else {
    browseDiscovery(discoveryMode, nextPage);
  }
});

$("#next-page").on("click", function () {
  const totalPages = Math.ceil(discoveryTotal / discoverySize);
  if (discoveryPage + 1 >= totalPages) {
    return;
  }
  const nextPage = discoveryPage + 1;
  if (discoveryMode === "search") {
    runSearch(nextPage);
  } else {
    browseDiscovery(discoveryMode, nextPage);
  }
});

function renderOpenReports(reports) {
  if (!reports.length) {
    $("#moderation-console").html("No open reports.");
    return;
  }

  const html = reports
    .map((report) => {
      const evidence = (report.evidenceFiles || []).join(", ") || "No evidence";
      return `
        <div class="search-item">
          <strong>Report #${report.reportId}</strong>
          <div>Reporter: ${report.reporterUser} | Reported: ${report.reportedUser}</div>
          <div>Reason: ${report.reason}</div>
          <div class="search-meta">Evidence: ${evidence}</div>
          <div class="reservation-tools">
            <select class="decision-penalty" data-report-id="${report.reportId}">
              <option value="MUTE_24H">24-hour mute</option>
              <option value="POST_RESTRICT_7D">7-day posting restriction</option>
              <option value="PERMANENT_BAN">Permanent ban</option>
              <option value="NO_ACTION">No action</option>
            </select>
            <input class="decision-notes" data-report-id="${report.reportId}" type="text" placeholder="Decision notes" />
            <button class="apply-decision" data-report-id="${report.reportId}" type="button">Apply Decision</button>
          </div>
        </div>
      `;
    })
    .join("");

  $("#moderation-console").html(html);
}

